const input = $input.first().json;
const topicId = input.topic_id;
const privacyStatus = input.privacy_status || 'public';

if (!topicId) throw new Error('Missing topic_id input');

return [{ json: { topicId, privacyStatus } }];

const topic = $('Load Topic Data').first().json[0] || $('Load Topic Data').first().json;
const project = topic.projects || {};
const scenes = $('Load Scenes').first().json;
const quotaResult = $('Check Daily Quota').first().json;
let privacyStatus = $('Parse Input').first().json.privacyStatus;

// Quota check: count uploads today
const uploadsToday = Array.isArray(quotaResult) ? quotaResult.length : 0;
const quotaExceeded = uploadsToday >= 6;

// If quota exceeded and trying to publish public, override to private
if (quotaExceeded && privacyStatus === 'public') {
  privacyStatus = 'private';
}

// Build chapter timestamps from scenes
const chapterMap = new Map();
const sceneList = Array.isArray(scenes) ? scenes : [];
for (const scene of sceneList) {
  if (scene.chapter && !chapterMap.has(scene.chapter)) {
    const ms = scene.start_time_ms || 0;
    const totalSec = Math.floor(ms / 1000);
    const h = Math.floor(totalSec / 3600);
    const m = Math.floor((totalSec % 3600) / 60);
    const s = totalSec % 60;
    const ts = `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`;
    chapterMap.set(scene.chapter, ts);
  }
}

const chapters = Array.from(chapterMap.entries())
  .map(([name, ts]) => `${ts} ${name}`)
  .join('\n');

// Build description
const meta = topic.script_metadata || {};
const hook = topic.narrative_hook || '';
const tags = meta.tags || [];
const hashtags = tags.slice(0, 5).map(t => '#' + t.replace(/\s+/g, '')).join(' ');

const description = [
  hook,
  '',
  'Chapters:',
  chapters || '00:00:00 Introduction',
  '',
  hashtags,
  '',
  '---',
  'Produced with Vision GridAI Platform'
].join('\n');

// Determine playlist ID
const playlistGroup = topic.playlist_group || 1;
const playlistId = playlistGroup === 1 ? project.youtube_playlist1_id
  : playlistGroup === 2 ? project.youtube_playlist2_id
  : project.youtube_playlist3_id;

const title = topic.seo_title || topic.original_title || 'Untitled Video';

return [{ json: {
  topicId: topic.id,
  projectId: project.id,
  title: title.substring(0, 100),
  description: description.substring(0, 5000),
  tags: tags.slice(0, 30),
  categoryId: '27',
  privacyStatus,
  scheduledPublishAt: topic.scheduled_publish_at || null,
  driveVideoUrl: topic.drive_video_url,
  driveFileId: topic.drive_video_url ? topic.drive_video_url.match(/\/d\/([^\/]+)/)?.[1] || '' : '',
  thumbnailUrl: topic.thumbnail_url,
  playlistId: playlistId || null,
  quotaExceeded,
  scenes: sceneList
} }];

const response = $input.first().json;
const uploadUri = response.headers?.location || response.headers?.Location || '';

if (!uploadUri) {
  throw new Error('No upload URI returned from YouTube resumable upload init. Headers: ' + JSON.stringify(response.headers));
}

return [{ json: { uploadUri } }];

const retryCount = ($input.first().json._retryCount || 0) + 1;
if (retryCount > 2) {
  throw new Error('Upload failed after 2 retries: ' + ($input.first().json.error || 'unknown error'));
}
return [{ json: { ...$input.first().json, _retryCount: retryCount } }];

const videoId = $('Upload Video to YouTube').first().json.id;
if (!videoId) throw new Error('No video ID from upload response');
return [{ json: { videoId } }];

const scenes = $('Prepare YouTube Metadata').first().json.scenes || [];

// Build SRT content from scenes
let srt = '';
let counter = 1;
for (const scene of scenes) {
  const startMs = scene.start_time_ms || 0;
  const endMs = scene.end_time_ms || (startMs + (scene.audio_duration_ms || 3000));
  const text = scene.narration_text || '';
  if (!text) continue;

  const formatTime = (ms) => {
    const totalSec = Math.floor(ms / 1000);
    const h = Math.floor(totalSec / 3600);
    const m = Math.floor((totalSec % 3600) / 60);
    const s = totalSec % 60;
    const milli = ms % 1000;
    return `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')},${String(milli).padStart(3,'0')}`;
  };

  srt += `${counter}\n${formatTime(startMs)} --> ${formatTime(endMs)}\n${text}\n\n`;
  counter++;
}

return [{ json: { srtContent: srt } }];

